import React from "react";
import img2 from "../img2.jpg";

function BannerTop() {
  const __height = window.innerHeight;
  return (
    <div>
      <img
        alt={"banner1"}
        style={{ width: "100%", height: __height / 2 - 10 }}
        src={img2}
      />
      <p className={"name"}>Michal Kurzal Porfolio</p>
    </div>
  );
}

export default BannerTop;
